  1	import * as React from 'react';
  2	
  3	import DurationDropdown from '@kubevirt-utils/components/DurationOption/DurationDropdown';
  4	import DurationOption from '@kubevirt-utils/components/DurationOption/DurationOption';
  5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  6	import useLocalStorage from '@kubevirt-utils/hooks/useLocalStorage';
  7	import { isEmpty } from '@kubevirt-utils/utils/utils';
  8	import { Overview } from '@openshift-console/dynamic-plugin-sdk';
  9	import {
 10	  Bullseye,
 11	  Card,
 12	  CardBody,
 13	  CardHeader,
 14	  CardTitle,
 15	  Grid,
 16	  GridItem,
 17	} from '@patternfly/react-core';
 18	
 19	import BandwidthConsumptionCharts from './components/BandwidthConsumptionCharts/BandwidthConsumptionCharts';
 20	import MigrationEmptyState from './components/MigrationEmptyState/MigrationEmptyState';
 21	import MigrationsChartDonut from './components/MigrationsChartDonut/MigrationsChartDonut';
 22	import MigrationsLimitionsPopover from './components/MigrationsLimitionsPopover/MigrationsLimitionsPopover';
 23	import MigrationTable from './components/MigrationsTable/MigrationsTable';
 24	import { getFilteredDurationVMIMS } from './components/MigrationsTable/utils/utils';
 25	import useMigrationCardDataAndFilters from './hooks/useMigrationCardData';
 26	import { MIGRATIONS_DURATION_KEY } from './utils/constants';
 27	
 28	import './MigrationsTab.scss';
 29	
 30	const MigrationsTab: React.FC = () => {
 31	  const { t } = useKubevirtTranslation();
 32	
 33	  const [duration, setDuration] = useLocalStorage(
 34	    MIGRATIONS_DURATION_KEY,
 35	    DurationOption.FIVE_MIN.toString(),
 36	  );
 37	
 38	  const migrationCardDataAndFilters = useMigrationCardDataAndFilters(duration);
 39	
 40	  const { onFilterChange, vmims } = migrationCardDataAndFilters || {};
 41	
 42	  const filteredVMIMS = getFilteredDurationVMIMS(vmims, duration);
 43	
 44	  const onDurationSelect = (value: string) =>
 45	    setDuration(DurationOption.fromDropdownLabel(value)?.toString());
 46	
 47	  return (
 48	    <Overview>
 49	      <Card data-test="kv-monitoring-card">
 50	        <CardHeader
 51	          actions={{
 52	            actions: (
 53	              <>
 54	                <div className="kv-top-consumers-card__dropdown--duration">
 55	                  <DurationDropdown selectedDuration={duration} selectHandler={onDurationSelect} />
 56	                </div>
 57	              </>
 58	            ),
 59	            className: 'co-overview-card__actions',
 60	            hasNoOffset: false,
 61	          }}
 62	          className="kv-monitoring-card__header"
 63	        >
 64	          <CardTitle>{t('VirtualMachineInstanceMigrations information')} </CardTitle>
 65	        </CardHeader>
 66	        <CardBody className="kv-monitoring-card__body">
 67	          {!isEmpty(filteredVMIMS) ? (
 68	            <Grid>
 69	              <GridItem className="kv-monitoring-card__graph-separator" span={6}>
 70	                <CardHeader
 71	                  actions={{
 72	                    actions: (
 73	                      <>
 74	                        <MigrationsLimitionsPopover />
 75	                      </>
 76	                    ),
 77	                    className: 'co-overview-card__actions',
 78	                    hasNoOffset: false,
 79	                  }}
 80	                >
 81	                  <CardTitle>{t('Migrations')}</CardTitle>
 82	                </CardHeader>
 83	                <CardBody className="kv-monitoring-card__body">
 84	                  <MigrationsChartDonut onFilterChange={onFilterChange} vmims={filteredVMIMS} />
 85	                </CardBody>
 86	              </GridItem>
 87	              <GridItem span={6}>
 88	                <CardHeader>
 89	                  <CardTitle>{t('Bandwidth consumption')}</CardTitle>
 90	                </CardHeader>
 91	                <CardBody className="kv-monitoring-card__body">
 92	                  <BandwidthConsumptionCharts duration={duration} />
 93	                </CardBody>
 94	              </GridItem>
 95	              <GridItem className="kv-monitoring-card__table-separator" span={12}>
 96	                <MigrationTable tableData={migrationCardDataAndFilters} />
 97	              </GridItem>
 98	            </Grid>
 99	          ) : (
100	            <Bullseye>
101	              <MigrationEmptyState />
102	            </Bullseye>
103	          )}
104	        </CardBody>
105	      </Card>
106	    </Overview>
107	  );
108	};
109	
110	export default MigrationsTab;

